import React, { useState } from 'react';
import styles from './PlayerTable.module.css';

// Small inline helper component to handle long roster wrapping layouts cleanly
function RosterCell({ athletes }) {
  const [expanded, setExpanded] = useState(false);
  
  if (!athletes || athletes.length === 0) return <span>—</span>;
  
  // Show only the first 5 athletes if not expanded
  const visibleAthletes = expanded ? athletes : athletes.slice(0, 5);
  const hasMore = athletes.length > 5;

  return (
    <div style={{ maxWidth: '400px' }}>
      <div style={{ 
        display: 'flex', 
        flexWrap: 'wrap', 
        gap: '4px', 
        maxHeight: expanded ? '200px' : '68px', 
        overflowY: expanded ? 'auto' : 'hidden',
        paddingRight: '4px'
      }}>
        {visibleAthletes.map((name, i) => (
          <span 
            key={i} 
            style={{
              fontSize: '11px',
              background: 'rgba(0,0,0,0.04)',
              border: '1px solid rgba(0,0,0,0.06)',
              padding: '2px 6px',
              borderRadius: '4px',
              color: 'var(--text)',
              whiteSpace: 'nowrap'
            }}
          >
            {name}
          </span>
        ))}
      </div>
      {hasMore && (
        <button
          type="button"
          onClick={() => setExpanded(!expanded)}
          style={{
            background: 'none',
            border: 'none',
            color: '#E8431A',
            fontSize: '11px',
            fontWeight: '600',
            cursor: 'pointer',
            padding: '4px 0 0 0',
            marginTop: '2px',
            display: 'block'
          }}
        >
          {expanded ? 'Hide Roster ↑' : `+${athletes.length - 5} more athletes ↓`}
        </button>
      )}
    </div>
  );
}

export default function TeamTable({
  data,
  total,
  page,
  pageSize,
  loading,
  sortBy,
  sortDir,
  onSort,
  onPage,
}) {
  const totalPages = Math.ceil(total / pageSize) || 1;

  const renderSortIcon = (key) => {
    if (sortBy !== key) return <span className={styles.sortNone}>↕</span>;
    return sortDir === 'asc' ? '↑' : '↓';
  };

  return (
    <div className={styles.tableWrapper}>
      <table className={styles.table} style={{ tableLayout: 'fixed', width: '100%' }}>
        <colgroup>
          <col style={{ width: '22%' }} />
          <col style={{ width: '15%' }} />
          <col style={{ width: '20%' }} />
          <col style={{ width: '33%' }} />
          <col style={{ width: '10%' }} />
        </colgroup>
        <thead>
          <tr>
            <th onClick={() => onSort('team_name')} className={styles.sortable}>
              Team Name {renderSortIcon('team_name')}
            </th>
            <th onClick={() => onSort('league')} className={styles.sortable}>
              League {renderSortIcon('league')}
            </th>
            <th onClick={() => onSort('coach')} className={styles.sortable}>
              Head Coach {renderSortIcon('coach')}
            </th>
            <th>Roster Athletes</th>
            <th onClick={() => onSort('roster_count')} className={styles.sortable}>
              Count {renderSortIcon('roster_count')}
            </th>
          </tr>
        </thead>
        <tbody>
          {loading ? (
            <tr><td colSpan={5} className={styles.center}>Loading roster details...</td></tr>
          ) : data.length === 0 ? (
            <tr><td colSpan={5} className={styles.center}>No teams found matching search inputs.</td></tr>
          ) : (
            data.map((team) => (
              <tr key={team.id || team.team_name} style={{ verticalAlign: 'top' }}>
                <td className={styles.bold} style={{ overflow: 'hidden', textOverflow: 'ellipsis', whiteSpace: 'nowrap' }}>
                  {team.team_name}
                </td>
                <td><span className={styles.badge}>{team.league}</span></td>
                <td style={{ fontSize: '13px', color: 'var(--text)' }}>{team.coach || '—'}</td>
                
                {/* Mounts the custom badge cell layout block engine */}
                <td>
                  <RosterCell athletes={team.athletes} />
                </td>
                
                <td className={styles.bold} style={{ textAlign: 'center' }}>{team.roster_count ?? 0}</td>
              </tr>
            ))
          )}
        </tbody>
      </table>

      {/* Pagination Footer Controls */}
      <div className={styles.pagination}>
        <span className={styles.pageInfo}>
          Showing {page * pageSize + 1} - {Math.min((page + 1) * pageSize, total)} of {total}
        </span>
        <div className={styles.pageButtons}>
          <button 
            disabled={page === 0 || loading} 
            onClick={() => onPage(page - 1)}
            className={styles.pageBtn}
          >
            Prev
          </button>
          <span className={styles.activePage}>{page + 1} / {totalPages}</span>
          <button 
            disabled={page >= totalPages - 1 || loading} 
            onClick={() => onPage(page + 1)}
            className={styles.pageBtn}
          >
            Next
          </button>
        </div>
      </div>
    </div>
  );
}
